import os

def rename_files(path):
    for root, dirs, files in os.walk(path):
        for filename in files:
            new_name = ''
            for word in filename.split('_'):
                new_name += word.title() + ' '
            new_name = new_name.strip()
            os.rename(os.path.join(root, filename), os.path.join(root, new_name))

